export class Ajv {
  constructor() {
    this.errors = null;
  }

  validateSchema() {
    this.errors = null;
    return true;
  }

  compile() {
    const validate = () => true;
    validate.errors = null;
    return validate;
  }

  errorsText(errors = this.errors) {
    return Array.isArray(errors) ? errors.map(error => error.message).join(', ') : '';
  }
}

export default Ajv;
